import React from "react";
import { withRouter } from "react-router";
import { Link } from "react-router-dom";
import MovieCard from "./MovieCard";
import { AppStore } from "../store/AppStore";
import empty from "../images/empty.svg";
function SearchPage({ movies, setMovies }) {
  const loading = AppStore.useState((s) => s.loading);
  return (
    <div className="search_page">
      {loading && (
        <div className="searchLoader" id="searchLoader">
          <div id="load">
            <div>G</div>
            <div>N</div>
            <div>I</div>
            <div>D</div>
            <div>A</div>
            <div>O</div>
            <div>L</div>
          </div>
        </div>
      )}
      <div id="close_holder">
        <Link
          to="/"
          onClick={() => {
            document.getElementById("searchInput").value = "";
            setMovies([]);
          }}
        >
          &times;
        </Link>
      </div>
      <div className="all_movies_holder">
        <div className="inner_all_movies_holder">
          {movies.map((movie) => (
            <MovieCard movie={movie} isLarge={false} />
          ))}
          {movies?.length == 0 && !loading ? (
            <div className="emptyDataHolder">
              <img src={empty} alt="empty" />
              <h1>No Data </h1>
            </div>
          ) : (
            ""
          )}
        </div>
      </div>
    </div>
  );
}

export default withRouter(SearchPage);
