import React, { useState, useEffect } from "react";
import axios from "../axios";
import requests from "../requests";

// import images
import searchIcon from "../images/search.svg";
import { useHistory } from "react-router";

import { AppStore } from "../store/AppStore";

function SearchBar({ Class, setMovies }) {
  const [showSearchMenu, setShowSearchMenu] = useState(false);
  const [searchTerm, setSearchTerm] = useState("");

  useEffect(() => {
    const reflexit = () => {
      setMovies([]);
      AppStore.update((s) => {
        s.loading = true;
      });
    };
    // evry time the input chnages setthe moviea query to that value
    const onChnageHandler = async (x) => {
      if (!showSearchMenu) return null;
      if (x === "") return null;

      const res = await axios.get(`${requests.multiFetch}&query=${x}`);
      setMovies(res.data.results);
      AppStore.update((s) => {
        s.loading = false;
      });
    };

    const delayDebounceFn = setTimeout(() => {
      onChnageHandler(searchTerm);
    }, 3000);
    reflexit();
    return () => clearTimeout(delayDebounceFn);
  }, [searchTerm]);
  // on click the search icon
  const onSubmitHandler = () => {
    console.log("search icon Clicked!");
  };
  const history = useHistory();
  return (
    <>
      <div className={Class} id="SearchBar">
        <input
          placeholder="type movie name"
          id="searchInput"
          onChange={(e) => setSearchTerm(e.target.value)}
          title="Double Click To Clear"
          onDoubleClick={(e) => {
            e.target.value = "";
            setMovies([]);
          }}
          onKeyDown={() => {
            setShowSearchMenu(true);
            history.push("/search-page");
          }}
        />
        <img src={searchIcon} alt="searchIcon" onClick={onSubmitHandler} />
      </div>
    </>
  );
}

export default SearchBar;
