import axios from "axios";
import React, { useState, useEffect } from "react";
import { useParams } from "react-router";
import requests from "../requests";
import MovieCard from "./MovieCard";

function AboutCast() {
  const { id, credit_id } = useParams();
  const [personData, setpersonData] = useState({});
  const [credit, setcredit] = useState({});
  useEffect(() => {
    const fetchData = async () => {
      const res1 = await axios.get(
        `https://api.themoviedb.org/3/person/${id}?api_key=${requests.apiKey}`
      );
      setpersonData(res1.data);
      const res2 = await axios.get(
        `https://api.themoviedb.org/3/credit/${credit_id}?api_key=${requests.apiKey}`
      );

      setcredit(res2.data);
    };
    fetchData();
  }, [id, credit_id]);
  return (
    <div className="AboutCastPage">
      <div className="innerAboutCastPage">
        <div className="ContentHolder">
          <img
            src={`${requests.image_api + personData.profile_path}`}
            alt={personData.name}
            className="castProfileImage"
          />
          <div className="textContentHolder">
            <h1 id="castName">about : {personData.name}</h1>
            <p id="biography">biography : {personData.biography}</p>
          </div>
        </div>
        <h2>also in</h2>
        <div className="KnownForHolder row__posters">
          {credit?.person?.known_for?.map((movie, key) => (
            <MovieCard movie={movie} key={key} />
          ))}
        </div>
      </div>
    </div>
  );
}

export default AboutCast;
