import React, { useEffect } from "react";
import SearchBar from "./SearchBar";
import WatchListButton from "./WatchListButton";
import { useMediaQuery } from "react-responsive";
import { useAuth0 } from "@auth0/auth0-react";
import { Link } from "react-router-dom";
import { CurrentUser } from "../store/User";

// firebase
import { db } from "../firebase-config";
import { setDoc, getDoc, doc } from "firebase/firestore";

function MenuBox({
  setMovieQuery,
  movies,
  setMovies,
  showSearchMenu,
  setShowSearchMenu,
  watchListLen,
  setIsLoading,
}) {
  const isSmallScreen = useMediaQuery({ query: "(max-width: 460px)" });
  const isBigScreen = useMediaQuery({ query: "(min-width: 564px)" });
  const { loginWithRedirect, user, isAuthenticated, isLoading } = useAuth0();

  useEffect(() => {
    setIsLoading(isLoading);
  }, [isLoading]);

  useEffect(() => {
    const whenUserLogIn = async () => {
      if (user && isAuthenticated) {
        const docSnap = await getDoc(doc(db, "users", user.sub));

        if (!docSnap.exists()) {
          await setDoc(doc(db, "users", user.sub), user);
        }

        CurrentUser.update((s) => {
          s.id = user.sub;
        });
      }
    };
    whenUserLogIn();
  }, [user]);

  return (
    <div className="MenuBox" id="MenuBox">
      {isBigScreen && (
        <SearchBar
          Class="SearchBar"
          setMovieQuery={setMovieQuery}
          movies={movies}
          setMovies={setMovies}
          showSearchMenu={showSearchMenu}
          setShowSearchMenu={setShowSearchMenu}
        />
      )}
      {!isAuthenticated && (
        <button
          className="loginButton WatchListButton"
          onClick={() => loginWithRedirect()}
        >
          login
        </button>
      )}
      {(isSmallScreen && !isAuthenticated) || !isSmallScreen ? (
        <WatchListButton watchListLen={watchListLen} />
      ) : (
        ""
      )}
      {isSmallScreen}
      {isAuthenticated && (
        <Link to="/account" className="accountLink">
          <img src={user?.picture} className="userAvatar"></img>
        </Link>
      )}
    </div>
  );
}

export default MenuBox;
